// Parse la réponse de l'AI pour détecter le JSON de commande
const aiResponse = $input.first().json.output || $input.first().json.message?.content || $input.first().json.text || '';

let action = 'reply';
let orderData = null;
let message = aiResponse;

// ─── Fonction de traitement d'une commande extraite ───────────────────────────
function processOrderData(parsed) {
  if (parsed.action !== 'create_order' || !parsed.data) return false;

  orderData = parsed.data;

  // Normalisation du numéro de téléphone → +596XXXXXXXXX
  if (orderData.client_phone) {
    const cleaned = orderData.client_phone.replace(/[\s\-\.]/g, '');
    if (!cleaned.startsWith('+596')) {
      const digits = cleaned.replace(/^\+?596/, '').replace(/^0/, '');
      orderData.client_phone = '+596' + digits;
    } else {
      orderData.client_phone = cleaned;
    }
  }

  // Normalisation de l'heure → HH:MM
  if (orderData.heure_souhaitee) {
    let h = String(orderData.heure_souhaitee).trim();
    // Convertir "19h30" → "19:30"
    h = h.replace(/h/i, ':');
    // Si pas de minutes, ajouter :00
    if (!h.includes(':')) h = h + ':00';
    // Padding : 9:30 → 09:30
    const parts = h.split(':');
    if (parts[0] && parts[0].length === 1) h = '0' + h;
    orderData.heure_souhaitee = h;
  }

  // Recalcul sécurisé du total (arrondi au centime)
  let calculatedTotal = 0;
  if (Array.isArray(orderData.items)) {
    orderData.items.forEach(item => {
      calculatedTotal += (Number(item.price) || 0) * (Number(item.quantity) || 1);
    });
  }
  if (orderData.type_service === 'delivery') {
    const deliveryFee = Number(orderData.delivery_fee) || 3;
    calculatedTotal += deliveryFee;
  }
  orderData.total = Math.round(calculatedTotal * 100) / 100;

  // delivery_address : null si click_collect
  if (orderData.type_service === 'click_collect') {
    orderData.delivery_address = null;
  }

  // Champs obligatoires
  orderData.notes = orderData.notes || 'Commande via CieloBot';
  orderData.status = 'pending_validation';

  action = 'create_order';
  message = '🎉 Commande envoyée ! Guylian va la valider très rapidement. Surveillez votre page de suivi : votre lien de paiement Stripe y apparaîtra automatiquement. À très vite chez Pizza dal Cielo ! 🍕';
  return true;
}

// ─── Extraction du JSON dans la réponse AI ────────────────────────────────────
const jsonPatterns = [
  /```json\s*\n?([\s\S]*?)\n?```/,
  /```\s*\n?([\s\S]*?)\n?```/,
  /(\{[\s\S]*"action"\s*:\s*"create_order"[\s\S]*\})/
];

for (const pattern of jsonPatterns) {
  const match = aiResponse.match(pattern);
  if (match) {
    try {
      const parsed = JSON.parse(match[1] || match[0]);
      if (processOrderData(parsed)) break;
    } catch (e) {
      // JSON invalide, continuer
    }
  }
}

// Tenter de parser la réponse entière si pas de bloc détecté
if (action === 'reply') {
  try {
    const parsed = JSON.parse(aiResponse.trim());
    processOrderData(parsed);
  } catch (e) {
    // Réponse texte normale, pas un JSON
  }
}

return {
  json: {
    action,
    message,
    orderData
  }
};

// Prépare la ligne à insérer dans Supabase
const input = $input.first().json;
const orderData = input.orderData;
const { randomUUID } = require('crypto');

// ── Calcul du delivery fee via l'API ──────────────────────────────────────
let deliveryFee = 0;
if (orderData.type_service === 'delivery') {
  let apiResult = null;
  try {
    apiResult = $('Calculate Delivery Fee').first()?.json;
  } catch(e) {}

  const apiFee = apiResult?.fee;

  // fee === null signifie explicitement hors zone (pas une erreur réseau)
  if (apiResult && !apiResult.error && apiFee === null) {
    const dist = apiResult.distanceKm ? ` (${apiResult.distanceKm} km)` : '';
    return [{ json: {
      action: 'error',
      message: `Désolé, votre adresse est en dehors de notre zone de livraison (7 km max autour de Bellevue)${dist}. Nous proposons le Click & Collect gratuit si vous préférez venir récupérer votre commande !`
    }}];
  }

  // Utiliser le fee API si disponible, sinon fallback sur l'estimation du bot
  deliveryFee = (apiFee !== undefined && apiFee !== null)
    ? Number(apiFee)
    : Number(orderData.delivery_fee) || 3;
}

// ── Normalisation des items : base + supplements → customizations + items séparés ──
function parseSupplementString(s) {
  // "Chorizo +3€" ou "Champignons frais de Paris +2€"
  const match = String(s).match(/^(.+?)\s*\+(\d+(?:\.\d+)?)\s*€?$/);
  if (match) return { name: match[1].trim(), price: parseFloat(match[2]) };
  return { name: String(s), price: 0 };
}

const convertedItems = [];
let supIdCounter = 9001;
if (Array.isArray(orderData.items)) {
  for (const item of orderData.items) {
    const { base, supplements, ...rest } = item;

    // Construire le tableau customizations
    const customizations = [];
    if (base) customizations.push(`Base: ${base}`);

    // Parser les suppléments
    const parsedSups = Array.isArray(supplements)
      ? supplements.map(s => typeof s === 'string' ? parseSupplementString(s) : s)
      : [];

    // Prix de base = prix AI - somme des suppléments (le bot intègre déjà les suppls)
    const supTotal = parsedSups.reduce((sum, s) => sum + (Number(s.price) || 0), 0);
    const rawPrice = Number(rest.price) || 0;
    const basePrice = Math.round((rawPrice - supTotal) * 100) / 100;

    convertedItems.push({
      ...rest,
      price: basePrice > 0 ? basePrice : rawPrice,
      customizations: customizations.length > 0 ? customizations : undefined,
    });

    // Ajouter chaque supplément comme item séparé (category: 'Suppléments')
    for (const sup of parsedSups) {
      if (sup.name) {
        convertedItems.push({
          id: supIdCounter++,
          name: sup.name,
          price: Number(sup.price) || 0,
          quantity: Number(item.quantity) || 1,
          category: 'Suppléments',
        });
      }
    }
  }
}
orderData.items = convertedItems;

// Recalcul du total avec le delivery fee réel
let calculatedTotal = 0;
for (const item of convertedItems) {
  calculatedTotal += (Number(item.price) || 0) * (Number(item.quantity) || 1);
}
calculatedTotal += deliveryFee;
orderData.total = Math.round(calculatedTotal * 100) / 100;

return [{ json: {
  id: randomUUID(),
  token: randomUUID(),
  created_at: new Date().toISOString(),
  client_name: orderData.client_name,
  client_phone: orderData.client_phone,
  type_service: orderData.type_service,
  heure_souhaitee: orderData.heure_souhaitee,
  items: orderData.items,
  total: orderData.total,
  status: 'pending_validation',
  notes: orderData.notes || 'Commande via CieloBot',
  delivery_address: orderData.delivery_address ?? null,
  delivery_fee: deliveryFee > 0 ? deliveryFee : null,
  refusal_reason: null,
  payment_link: null,
  estimated_ready_time: null,
  actual_ready_time: null,
  preparation_started_at: null,
  completed_at: null,
}}];

const orderResponse = $input.first().json;
const previousData = $('Parse Response').first().json;
const APP_URL = 'https://pizzadalcielo.com';

// Le node Supabase natif retourne l'objet directement : { id, token, ... }
let orderRow = null;
if (orderResponse && orderResponse.token) {
  orderRow = orderResponse;
}

if (orderRow && orderRow.token) {
  const trackingUrl = `${APP_URL}/order/${orderRow.token}`;
  return {
    json: {
      action: 'create_order',
      message: `${previousData.message}\n\n🔗 Suivre votre commande : ${trackingUrl}`,
      token: orderRow.token,
      orderId: orderRow.id,
      trackingUrl,
      success: true
    }
  };
} else {
  return {
    json: {
      action: 'reply',
      message: '😔 Notre système est momentanément indisponible. Vous pouvez nous appeler directement au +596 696 88 72 70 ou passer commande sur pizzadalcielo.com. Toutes nos excuses !',
      success: false
    }
  };
}

const data = $input.first().json;
let message = data.message || '';
let quickReplies = null;
const match = message.match(/\[REPONSES_RAPIDES\]\s*:\s*([^\n]+)/);
if (match) {
  quickReplies = match[1].split('|').map(s => s.trim()).filter(Boolean);
  message = message.replace(/\s*\[REPONSES_RAPIDES\]\s*:[^\n]*\n?/g, '').trim();
}
return {
  json: {
    action: 'reply',
    message,
    ...(quickReplies && quickReplies.length && { quickReplies })
  }
};

const { chatInput, sessionId } = $('Edit Fields').first().json;

// ── Heure locale Martinique ────────────────────────────────────────────────
const now = new Date();
const mqStr = (opts) => now.toLocaleString('fr-FR', { timeZone: 'America/Martinique', ...opts });
const dayName = mqStr({ weekday: 'long' });
const timeStr = mqStr({ hour: '2-digit', minute: '2-digit' });
const localDate = new Date(now.toLocaleString('en-US', { timeZone: 'America/Martinique' }));
const dayNum = localDate.getDay(); // 0=Dim, 1=Lun, 2=Mar ... 6=Sam
const hour = localDate.getHours();
const isOpenDay = dayNum >= 2 && dayNum <= 6;
const isOpenHour = hour >= 18 && hour < 22;
const isOpen = isOpenDay && isOpenHour;

let timeContext = `Date/Heure Martinique : ${dayName} ${timeStr}`;
if (!isOpenDay) {
  timeContext += ' — RESTAURANT FERMÉ aujourd\'hui (ouvert Mardi à Samedi uniquement)';
} else if (hour < 18) {
  timeContext += ` — Restaurant pas encore ouvert (ouverture à 18h00)`;
} else if (hour >= 22) {
  timeContext += ` — Restaurant fermé pour ce soir (fermeture à 22h00)`;
} else {
  timeContext += ' — Restaurant OUVERT';
}

// ── État du four ───────────────────────────────────────────────────────────
let queueContext = '';
try {
  const q = $('Fetch Queue Status').first().json;
  if (q.ovenAvailable === false) {
    queueContext = '⚠️ FOUR INDISPONIBLE en ce moment — informer le client et ne pas prendre de commande pizza.';
  } else if (q.estimatedMinutes !== undefined) {
    const src = q.estimateSource === 'manual' ? ' (estimation manuelle de Guylian)' : '';
    const load = q.estimatedMinutes <= 20 ? 'Four disponible' : q.estimatedMinutes <= 40 ? 'Four chargé' : 'Four très chargé';
    queueContext = `${load} — attente estimée : ~${q.estimatedMinutes} min${src}`;
  } else {
    queueContext = 'Four disponible — aucune commande en cours';
  }
} catch {
  queueContext = 'État du four : information temporairement indisponible';
}

// ── Pizza du Chef du moment ────────────────────────────────────────────────
let chefContext = '';
try {
  const c = $('Fetch Chef Pizza').first().json;
  const p = c.product;
  if (p && p.name) {
    chefContext = `Pizza du Chef du moment : "${p.name}" — ${p.price}€`;
    if (p.description) chefContext += ` — ${p.description}`;
    if (p.ingredients && Array.isArray(p.ingredients) && p.ingredients.length) {
      chefContext += ` — Ingrédients : ${p.ingredients.join(', ')}`;
    }
    if (p.chef_valid_until) {
      const until = new Date(p.chef_valid_until);
      const untilStr = until.toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', timeZone: 'America/Martinique' });
      chefContext += ` (disponible jusqu'au ${untilStr})`;
    }
  } else {
    chefContext = 'Pizza du Chef : aucune création spéciale configurée ce soir';
  }
} catch {
  chefContext = 'Pizza du Chef : information temporairement indisponible';
}

// ── Menu en direct (prix réels depuis la base de données) ─────────────────
let menuContext = '';
try {
  const menuData = $('Fetch Menu').first().json;
  const items = Array.isArray(menuData.items) ? menuData.items : [];
  if (items.length > 0) {
    // Grouper par catégorie
    const groups = {};
    const ORDER = ['Classique', 'Friands', 'Boissons', 'Desserts'];
    for (const item of items) {
      const cat = item.category || item.type;
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(item);
    }
    const lines = ['MENU TEMPS RÉEL — ces prix et disponibilités font foi :'];
    const cats = [...ORDER.filter(c => groups[c]), ...Object.keys(groups).filter(c => !ORDER.includes(c))];
    for (const cat of cats) {
      lines.push(`\n━━━ ${cat.toUpperCase()} ━━━`);
      for (const item of groups[cat]) {
        const unavail = item.available === false ? ' ⛔ INDISPONIBLE' : '';
        const ingr = Array.isArray(item.ingredients) && item.ingredients.length
          ? ` — ${item.ingredients.join(', ')}`
          : '';
        const sauce = item.sauce_au_choix ? ' + sauce au choix après cuisson' : '';
        const size = item.size ? ` ${item.size}` : '';
        lines.push(`- ${item.name}${size} : ${item.price}€ (id: ${item.menu_id})${ingr}${sauce}${unavail}`);
      }
    }
    menuContext = lines.join('\n');
  }
} catch {
  menuContext = 'Menu : information temporairement indisponible — utiliser les prix du system prompt';
}

const contextBlock = `[INFOS TEMPS RÉEL — ne pas afficher au client, utiliser uniquement pour répondre de façon pertinente]\n${timeContext}\n${queueContext}\n${chefContext}\n${menuContext}\n[FIN INFOS]\n\n`;

return { json: { chatInput: contextBlock + chatInput, sessionId } };
